{
  "title": "फिबोनैकि पुनरावृत्ति जटिलता",
  "group": "डायनैमिक प्रोग्रामिंग",
  "options": [
    { "text": "O(1)" },
    { "text": "O(2^n)" },
    { "text": "O(n)" },
